{
  "name": "session-bridge",
  "displayName": "Session Bridge",
  "description": "Unofficial VSCode extension for inspecting and managing Entire sessions and checkpoints",
  "version": "0.0.1",
  "publisher": "kirk-agbenyegah",
  "repository": "https://github.com/savekirk/session-bridge",
  "bugs": {
    "url": "https://github.com/savekirk/session-bridge/issues"
  },
  "engines": {
    "vscode": "^1.105.0"
  },
  "categories": [
    "Other"
  ],
  "activationEvents": [
    "workspaceContains:**/*",
    "onIssueReporterOpened"
  ],
  "main": "./dist/extension.js",
  "contributes": {
    "viewsContainers": {
      "activitybar": [
        {
          "id": "session-bridge",
          "title": "Session Bridge for Entire",
          "icon": "media/logo.svg"
        }
      ]
    },
    "views": {
      "session-bridge": [
        {
          "id": "session.bridge.entire.checkpoints",
          "name": "Checkpoints",
          "icon": "media/dark/history.svg"
        },
        {
          "id": "session.bridge.entire.sessions",
          "name": "Checkpoint Sessions",
          "icon": "media/dark/history.svg"
        }
      ]
    },
    "viewsWelcome": [
      {
        "view": "session.bridge.entire.checkpoints",
        "when": "gitOpenRepositoryCount == 0",
        "contents": "Open a Git repository to view Entire checkpoints.\n[Open Folder](command:vscode.openFolder)\nTo learn more about Entire [read the docs](https://docs.entire.io)"
      },
      {
        "view": "session.bridge.entire.checkpoints",
        "when": "gitOpenRepositoryCount != 0 && session.bridge.state.cli-missing",
        "contents": "The Entire CLI is not available in the extension host environment.\nTo learn more about Entire [read the docs](https://docs.entire.io)"
      },
      {
        "view": "session.bridge.entire.checkpoints",
        "when": "gitOpenRepositoryCount != 0 && session.bridge.state.not-git-repo",
        "contents": "Entire features require a Git repository.\n[Open Folder](command:vscode.openFolder)\nTo learn more about Entire [read the docs](https://docs.entire.io)"
      },
      {
        "view": "session.bridge.entire.checkpoints",
        "when": "gitOpenRepositoryCount != 0 && session.bridge.state.disabled",
        "contents": "Entire is not enabled for this repository.\n[Enable In Repository](command:session.bridge.entire.enable)\nTo learn more about Entire [read the docs](https://docs.entire.io)"
      },
      {
        "view": "session.bridge.entire.sessions",
        "when": "session.bridge.state.not-git-repo",
        "contents": "Open a Git repository to see checkpoint sessions."
      },
      {
        "view": "session.bridge.entire.sessions",
        "when": "session.bridge.state.cli-missing",
        "contents": "Checkpoint sessions will appear here after Entire is installed and enabled."
      },
      {
        "view": "session.bridge.entire.sessions",
        "when": "session.bridge.state.disabled",
        "contents": "Checkpoint sessions will appear here after Entire is enabled."
      },
      {
        "view": "session.bridge.entire.sessions",
        "when": "session.bridge.state.enabled",
        "contents": "Select a checkpoint to inspect only the sessions captured in that checkpoint.\n[Refresh session state](command:session.bridge.entire.refresh)"
      },
      {
        "view": "session.bridge.entire.checkpoints",
        "when": "session.bridge.state.enabled",
        "contents": "No checkpoints on this branch.\n[Refresh checkpoint state](command:session.bridge.entire.refresh)"
      }
    ],
    "commands": [
      {
        "command": "session.bridge.entire.showStatus",
        "title": "Show Status",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.enable",
        "title": "Enable In Repository",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.disable",
        "title": "Disable In Repository",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.refresh",
        "title": "Refresh",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.fetchCheckpointBranch",
        "title": "Fetch Checkpoint Branch",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.browseCheckpoints",
        "title": "Browse Checkpoints",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.clean",
        "title": "Clean Entire State",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.reset",
        "title": "Reset Entire Session Data",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.showTrace",
        "title": "Show Trace",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.configure",
        "title": "Configure Entire",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.doctor",
        "title": "Run Doctor",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.resume",
        "title": "Resume Session",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.rewind",
        "title": "Rewind Session",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.explain",
        "title": "Explain Session",
        "category": "Session Bridge (Entire)"
      },
      {
        "command": "session.bridge.entire.reportIssue",
        "title": "Report Issue",
        "category": "Session Bridge (Entire)"
      }
    ],
    "menus": {
      "view/title": [
        {
          "command": "session.bridge.entire.refresh",
          "when": "view =~ /^session\\.bridge\\.entire\\./",
          "group": "navigation"
        },
        {
          "command": "session.bridge.entire.reportIssue",
          "when": "view =~ /^session\\.bridge\\.entire\\./",
          "group": "1_help"
        }
      ]
    }
  },
  "scripts": {
    "vscode:prepublish": "pnpm run package",
    "compile": "pnpm run check-types && pnpm run lint && node esbuild.js",
    "watch": "npm-run-all -p watch:*",
    "watch:esbuild": "node esbuild.js --watch",
    "watch:tsc": "tsc --noEmit --watch --project tsconfig.json",
    "package": "pnpm run check-types && pnpm run lint && node esbuild.js --production",
    "compile-tests": "node -e \"require('node:fs').rmSync('out', { recursive: true, force: true })\" && tsc -p . --outDir out",
    "watch-tests": "tsc -p . -w --outDir out",
    "pretest": "pnpm run compile-tests && pnpm run compile && pnpm run lint",
    "check-types": "tsc --noEmit",
    "lint": "eslint src",
    "test": "vscode-test"
  },
  "devDependencies": {
    "@types/vscode": "1.105.0",
    "@types/mocha": "^10.0.10",
    "@types/node": "22.x",
    "typescript-eslint": "^8.56.1",
    "eslint": "^9.39.3",
    "esbuild": "^0.27.3",
    "npm-run-all": "^4.1.5",
    "typescript": "^5.9.3",
    "@vscode/test-cli": "^0.0.12",
    "@vscode/test-electron": "^2.5.2"
  }
}
